runner = InMemoryRunner(agent=agent, app_name=APP_NAME)


# --- JSON extraction helper ---------------------------------------------------

def _extract_json(text: str) -> str:
    """Extract the outermost JSON object from LLM text.

    Handles: pure JSON, JSON in ```json fences, JSON with a prose preamble.
    Raises ValueError when no valid JSON object boundary is found.
    """
    stripped = text.strip()
    # Fast path: already bare JSON
    if stripped.startswith("{"):
        return stripped
    # Strip code fences (```json ... ``` or ``` ... ```)
    fence = re.search(r"```(?:json)?\s*(\{.*\})\s*```", stripped, re.DOTALL)
    if fence:
        return fence.group(1)
    # Find outermost { ... } by brace counting
    start = text.find("{")
    if start == -1:
        raise ValueError("No JSON object found in LLM response")
    depth = 0
    for i, ch in enumerate(text[start:], start):
        if ch == "{":
            depth += 1
        elif ch == "}":
            depth -= 1
            if depth == 0:
                return text[start : i + 1]
    raise ValueError("Unmatched braces — JSON object not closed in LLM response")


# --- One-shot LLM helper (the executor's `fulfill` work hook) ------------------

_log = logging.getLogger("seller-agent")


async def _call_runner(prompt: str, session_id: str) -> str:
    """Run the ADK runner once and return raw final-response text (thought-filtered)."""
    session_service = runner.session_service
    existing = await session_service.get_session(
        app_name=runner.app_name, user_id="service", session_id=session_id
    )
    if existing is None:
        await session_service.create_session(
            app_name=runner.app_name, user_id="service", session_id=session_id
        )
    user_msg = gtypes.Content(role="user", parts=[gtypes.Part(text=prompt)])
    parts: list[str] = []
    async for event in runner.run_async(
        user_id="service", session_id=session_id, new_message=user_msg
    ):
        if event.is_final_response() and event.content:
            for p in event.content.parts:
                if p.text and not getattr(p, "thought", False):
                    parts.append(p.text)
    return "\n".join(parts).strip()


def _try_parse_report(text: str) -> StockReport | None:
    """Extract + parse + validate the StockReport JSON from LLM text. Returns None on failure."""
    try:
        json_str = _extract_json(text)
        return StockReport.model_validate_json(json_str)
    except Exception as exc:
        _log.warning("report parse/validation failed: %s", exc)
        return None


async def _run_llm(
    prompt: str,
    *,
    session_id: str,
    symbols: list[str] | None = None,
) -> str:
    """Run the agent, parse its JSON output, validate the schema, render Markdown.

    Flow:
      1. Call the ADK runner → raw LLM text (thinking stripped).
      2. Extract the JSON object from the text.
      3. Parse + validate with StockReport (Pydantic).
      4. Check that every requested symbol has an analyses entry.
      5. Render to institutional Markdown via report_renderer.
      On parse/validation failure: retry once with a correction prompt,
      then fall back to delivering the raw LLM text so the buyer always gets
      something.
    """
    raw = await _call_runner(prompt, session_id)

    report = _try_parse_report(raw)

    if report is None:
        # Retry: ask the model to fix its output in the same session
        _log.info("retrying with correction prompt (session %s)", session_id)
        correction = (
            "Your previous response could not be parsed as valid JSON matching the StockReport schema. "
            "Output ONLY the corrected JSON object — no text before or after it, no code fences. "
            "Ensure the analyses array has one entry per symbol and all required fields are present."
        )
        raw2 = await _call_runner(correction, session_id)
        report = _try_parse_report(raw2)

    if report is None:
        _log.error("structured output failed after retry (session %s); delivering raw text", session_id)
        return raw  # fall back: buyer still gets the LLM text

    # Validate symbol completeness (code-level, not prompt-level)
    if symbols:
        returned = {a.symbol.upper() for a in report.analyses}
        missing = [s for s in symbols if s.upper() not in returned]
        if missing:
            _log.warning("analyses missing for symbols %s (session %s)", missing, session_id)
            # Deliver what we have — partial is better than nothing

    return render_report(report)


async def _stream_runner(
    prompt: str,
    session_id: str,
    symbols: list[str] | None = None,
) -> AsyncGenerator[tuple[str, dict], None]:
    """Async generator for SSE streaming: yields (event_name, data) tuples.

    Used by the x402 channel (X402Handler) to push live progress events and
    the final rendered report over a single HTTP connection. Not used by the
    ERC-8183 A2A path (which delivers async via submit_result on-chain).

    Yields:
      ("progress", {"stage": "collecting", "tool": <name>, "message": ...})
      ("progress", {"stage": "generating", "message": "Rendering report..."})
      ("report",   {"content": <markdown>, "format": "markdown"})
      ("done",     {})
    """
    session_service = runner.session_service
    existing = await session_service.get_session(
        app_name=runner.app_name, user_id="service", session_id=session_id
    )
    if existing is None:
        await session_service.create_session(
            app_name=runner.app_name, user_id="service", session_id=session_id
        )

    user_msg = gtypes.Content(role="user", parts=[gtypes.Part(text=prompt)])
    parts: list[str] = []

    async for event in runner.run_async(
        user_id="service", session_id=session_id, new_message=user_msg
    ):
        if event.content:
            for part in event.content.parts:
                fn_call = getattr(part, "function_call", None)
                if fn_call:
                    tool_name = getattr(fn_call, "name", str(fn_call))
                    yield "progress", {
                        "stage": "collecting",
                        "tool": tool_name,
                        "message": f"Running {tool_name}...",
                    }
        if event.is_final_response() and event.content:
            for p in event.content.parts:
                if p.text and not getattr(p, "thought", False):
                    parts.append(p.text)

    raw = "\n".join(parts).strip()

    yield "progress", {"stage": "generating", "message": "Rendering report..."}

    report = _try_parse_report(raw)
    if report is None:
        # Fallback: deliver raw text (buyer still gets something)
        _log.warning("x402 stream: structured parse failed; delivering raw text (session %s)", session_id)
        yield "report", {"content": raw, "format": "text"}
    else:
        if symbols:
            returned = {a.symbol.upper() for a in report.analyses}
            missing = [s for s in symbols if s.upper() not in returned]
            if missing:
                _log.warning("x402 stream: missing analyses for %s (session %s)", missing, session_id)
        yield "report", {"content": render_report(report), "format": "markdown"}

    yield "done", {}


def _default_network() -> str:
    """studio.toml ``[network].default`` (best-effort; used by the funded sweep)."""
    try:
        from bnbagent_studio_core import config

        return str(((config.load_studio_toml() or {}).get("network") or {}).get("default") or "bsc-testnet")
    except Exception:  # noqa: BLE001
        return "bsc-testnet"


# --- A2A surface --------------------------------------------------------------
# The executor backs the seller skills with signing.py fixed code (NEVER an LLM
# tool). serve_a2a (AgentCore SDK, built on the official a2a-sdk) hosts the agent
# card + JSON-RPC message/send on 0.0.0.0:9000, adds GET /ping, and overwrites
# the card url with the deployed runtime URL ($AGENTCORE_RUNTIME_URL).
executor = SellerAgentExecutor(
    run_work=_run_llm, generator=GENERATOR, network=_default_network()
)
agent_card = build_agent_card()


def _ping_status():
    """GET /ping status fed to AgentCore: HEALTHY_BUSY while a background delivery
    is in flight, else HEALTHY.

    notify_funded acks immediately and runs the slow work (LLM + on-chain submit)
    in the background. Reporting HEALTHY_BUSY tells AgentCore the runtime is still
    working, so the scale-to-zero runtime is NOT reaped on idle before delivery
    lands (bounded by the session max-lifetime; ≤8h)."""
    from bedrock_agentcore.runtime.models import PingStatus

    return PingStatus.HEALTHY_BUSY if executor.is_busy() else PingStatus.HEALTHY


# --- JSON-RPC error hardening -------------------------------------------------
# a2a-sdk builds -32602 (InvalidParams) / -32600 (InvalidRequest) JSON-RPC error
# responses from a Pydantic ValidationError, and Pydantic embeds an ``input`` key
# in each error entry that echoes the caller's raw request body back to them
# (a2a/server/apps/jsonrpc/jsonrpc_app.py). It only ever reflects the CALLER'S OWN
# input to that same caller (not cross-tenant), so this is low-severity, but we
# strip ``input`` from outgoing JSON-RPC error data anyway — no reason to echo
# request bodies. This is a tiny pure-ASGI wrapper (no SDK edit) that rewrites the
# response body only for JSON-RPC error payloads; every other response passes
# through untouched.
def _strip_error_input(app):
    async def _wrapped(scope, receive, send):
        if scope["type"] != "http":
            await app(scope, receive, send)
            return

        # `buffer` is decided from the response start (content-type): we only
        # buffer+rewrite JSON bodies (the JSON-RPC error path). SSE / any other
        # response streams through unbuffered so streaming is never broken.
        state: dict = {"buffer": False, "start": None}
        chunks: list[bytes] = []

        async def _capture(message):
            if message["type"] == "http.response.start":
                ctype = dict(message.get("headers", [])).get(b"content-type", b"")
                state["buffer"] = b"application/json" in ctype.lower()
                state["start"] = message
                if not state["buffer"]:
                    await send(message)
            elif message["type"] == "http.response.body":
                if not state["buffer"]:
                    await send(message)
                    return
                chunks.append(message.get("body", b"") or b"")
                if message.get("more_body"):
                    return
                await _emit(send, state["start"], b"".join(chunks))
            else:
                await send(message)

        await app(scope, receive, _capture)

    return _wrapped


async def _emit(send, start_message, body: bytes):
    new_body = body
    try:
        payload = json.loads(body)
        # JSON-RPC error: {"jsonrpc": "2.0", "error": {"data": [ {...,"input":..}]}}
        data = payload.get("error", {}).get("data")
        if isinstance(data, list) and any(
            isinstance(e, dict) and "input" in e for e in data
        ):
            for e in data:
                if isinstance(e, dict):
                    e.pop("input", None)
            new_body = json.dumps(payload).encode("utf-8")
    except Exception:  # noqa: BLE001 — never let hardening break a response
        new_body = body

    if start_message is not None:
        headers = [
            (k, v)
            for (k, v) in start_message.get("headers", [])
            if k.lower() != b"content-length"
        ]
        headers.append((b"content-length", str(len(new_body)).encode("latin-1")))
        start_message = {**start_message, "headers": headers}
        await send(start_message)
    await send({"type": "http.response.body", "body": new_body, "more_body": False})


if __name__ == "__main__":
    import re
    from pathlib import Path

    import uvicorn
    from bedrock_agentcore.runtime import build_a2a_app

    app = build_a2a_app(executor, agent_card, ping_handler=_ping_status)
    app = _strip_error_input(app)

    # Serve local-storage deliverables at /erc8183/job/{id}/response so that
    # ERC8183_AGENT_URL=http://localhost:9000/erc8183 works in local dev.
    # The LocalStorageProvider writes job-{id}.json into STORAGE_LOCAL_PATH.
    _inner = app
    _storage_dir = Path(os.environ.get("STORAGE_LOCAL_PATH") or ".agent-data")

    async def _app(scope, receive, send):
        if scope["type"] == "http":
            path = scope.get("path", "")
            m = re.match(r"^/erc8183/job/(\d+)/response$", path)
            if m:
                fpath = _storage_dir / f"erc8183-job-{m.group(1)}.json"
                if fpath.exists():
                    body = fpath.read_bytes()
                    await send({"type": "http.response.start", "status": 200,
                                "headers": [(b"content-type", b"application/json"),
                                            (b"content-length", str(len(body)).encode())]})
                    await send({"type": "http.response.body", "body": body})
                else:
                    await send({"type": "http.response.start", "status": 404, "headers": []})
                    await send({"type": "http.response.body", "body": b"not found"})
                return
        await _inner(scope, receive, send)

    # --- x402 / Binance Pay channel -------------------------------------------
    # Mount the x402 handler as the outermost ASGI layer so it intercepts
    # /x402/* before the A2A server, the ERC-8183 local-storage route, and
    # the JSON-RPC error-hardening middleware. Payment verification and SSE
    # streaming are fixed code — the LLM sees only the analysis prompt.
    from x402_handler import X402Handler
    _app = X402Handler(
        _app,
        stream_work=_stream_runner,
        generator=GENERATOR,
    )

    uvicorn.run(
        _app,
        host=os.environ.get("AGENT_BIND_HOST") or "0.0.0.0",
        port=int(os.environ.get("AGENT_PORT") or "9000"),
        log_level="info",
    )
